        _tx_apps ??= new List<ulong>();
        _tx_accounts ??= new List<Address>();
        byte[] abiHandle = { 205, 96, 234, 104 };
        var preimageAbi = new AVM.ClientGenerator.ABI.ARC4.Types.VariableArray<AVM.ClientGenerator.ABI.ARC4.Types.Byte>("byte"); preimageAbi.From(preimage);
        var encryptionPubkeyAbi = new AVM.ClientGenerator.ABI.ARC4.Types.FixedArray<AVM.ClientGenerator.ABI.ARC4.Types.Byte>(32, "byte"); encryptionPubkeyAbi.From(encryptionPubkey);
