        byte[] abiHandle = { 107, 16, 156, 211 };
        var initialPriceAbi = new AVM.ClientGenerator.ABI.ARC4.Types.UInt64(); initialPriceAbi.From(initialPrice);

        var result = await base.CallApp(new List<object> { abiHandle, initialPriceAbi }, _tx_fee: _tx_fee, _tx_callType: _tx_callType, _tx_roundValidity: _tx_roundValidity, _tx_note: _tx_note, _tx_sender: _tx_sender, _tx_transactions: _tx_transactions, _tx_apps: _tx_apps, _tx_assets: _tx_assets, _tx_accounts: _tx_accounts, _tx_boxes: _tx_boxes);

