    ///<summary>
    ///Test-only ABI exposing the bare Groth16 verifier. Lets CI drive
    ///`verifyGroth16` against committed golden vectors without the surrounding
    ///`redeemWithProof` flow (which lands in T5). Returns `true`/`false` so a
    ///failing proof does NOT revert here — the caller asserts on the return
    ///value.
    ///
    ///Safe to ship: leaks no state, takes no side effects, and only validates
    ///proofs against the embedded vk. Production callers (`redeemWithProof`)
    ///should depend on the underlying `verifyGroth16` import directly, not on
    ///this wrapper.
    ///</summary>
    /// <param name="proof"> </param>
    /// <param name="publicInputs"> </param>
    public async Task<bool> VerifyProofForTest(byte[] proof, byte[] publicInputs, Account _tx_sender, ulong? _tx_fee, string _tx_note = "", ulong _tx_roundValidity = 1000, List<BoxRef>? _tx_boxes = null, List<Transaction>? _tx_transactions = null, List<ulong>? _tx_assets = null, List<ulong>? _tx_apps = null, List<Address>? _tx_accounts = null, AVM.ClientGenerator.Core.OnCompleteType _tx_callType = AVM.ClientGenerator.Core.OnCompleteType.NoOp)
    {
        _tx_boxes ??= new List<BoxRef>();
        _tx_transactions ??= new List<Transaction>();
        _tx_assets ??= new List<ulong>();
        _tx_apps ??= new List<ulong>();
        _tx_accounts ??= new List<Address>();
        byte[] abiHandle = { 224, 123, 103, 13 };
        var proofAbi = new AVM.ClientGenerator.ABI.ARC4.Types.VariableArray<AVM.ClientGenerator.ABI.ARC4.Types.Byte>("byte"); proofAbi.From(proof);
        var publicInputsAbi = new AVM.ClientGenerator.ABI.ARC4.Types.VariableArray<AVM.ClientGenerator.ABI.ARC4.Types.Byte>("byte"); publicInputsAbi.From(publicInputs);

        var result = await base.CallApp(new List<object> { abiHandle, proofAbi, publicInputsAbi }, _tx_fee: _tx_fee, _tx_callType: _tx_callType, _tx_roundValidity: _tx_roundValidity, _tx_note: _tx_note, _tx_sender: _tx_sender, _tx_transactions: _tx_transactions, _tx_apps: _tx_apps, _tx_assets: _tx_assets, _tx_accounts: _tx_accounts, _tx_boxes: _tx_boxes);
        var lastLogBytes = result.Last();
        if (lastLogBytes.Length < 4 || lastLogBytes[0] != 21 || lastLogBytes[1] != 31 || lastLogBytes[2] != 124 || lastLogBytes[3] != 117) throw new Exception("Invalid ABI handle");
        var lastLogReturnData = lastLogBytes.Skip(4).ToArray();
        var returnValueObj = new AVM.ClientGenerator.ABI.ARC4.Types.Bool();
        returnValueObj.Decode(lastLogReturnData);
        return BitConverter.ToBoolean(ReverseIfLittleEndian(lastLogReturnData), 0);

    }

